const day = 3;
switch (day) {
  case 1: console.log('Mon'); break;
  case 3: console.log('Wed'); break;
  default: console.log('?');
}

day = 3
if day == 1:
    print('Mon')
elif day == 3:
    print('Wed')
else:
    print('?')

int day = 3;
switch (day) {
    case 1: System.out.println("Mon"); break;
    case 3: System.out.println("Wed"); break;
    default: System.out.println("?");
}
